<template><section class="panel explore-view"><div class="section-head"><div><h2>里界探索</h2><p>跑团式短程探索：选择身份卡，可携带一件伪物，掷骰后获得本真，可能带回新伪物。</p></div><button class="primary" :disabled="running" @click="run">{{ running?'探索中':'开始探索' }}</button></div><div class="form-grid"><label>身份卡<select v-model="cardId"><option value="0">不用身份卡</option><option v-for="c in cards" :key="c.id" :value="c.id">{{ c.source_name }}</option></select></label><label>携带伪物<select v-model="artifactId"><option value="0">不携带</option><option v-for="i in inventory" :key="i.id" :value="i.id">{{ i.name }}</option></select></label></div><article v-if="result" class="run-result"><h3>探索记录</h3><p>{{ result.result }}</p><b>获得 {{ result.reward }} 本真</b><div v-if="result.artifact" class="artifact-drop">带回伪物：{{ result.artifact.name }}</div></article><section class="history"><h3>近期探索</h3><article v-for="r in runs" :key="r.id" class="review-item"><b>{{ r.area }} · {{ r.danger }}</b><small>{{ new Date(r.created_at*1000).toLocaleString() }}</small><p>{{ r.result }}</p></article></section></section></template>
<script setup>
import { onMounted, ref } from 'vue'; import { siteApi, sessionHeaders } from '../lib/api.js'
const props=defineProps({session:String}); const cards=ref([]), inventory=ref([]), runs=ref([]), cardId=ref('0'), artifactId=ref('0'), result=ref(null), running=ref(false)
async function load(){cards.value=await siteApi('/api/identity-cards',{headers:sessionHeaders(props.session)}).catch(()=>[]); const inv=await siteApi('/api/inventory',{headers:sessionHeaders(props.session)}).catch(()=>({items:[]})); inventory.value=inv.items||[]; runs.value=await siteApi('/api/explore/runs',{headers:sessionHeaders(props.session)}).catch(()=>[])}
async function run(){running.value=true; try{result.value=await siteApi('/api/explore/run',{method:'POST',headers:sessionHeaders(props.session),body:JSON.stringify({card_id:Number(cardId.value),artifact_id:Number(artifactId.value)})}); await load()}finally{running.value=false}}
onMounted(load)
</script>